sql:
SELECT facility_id
FROM capacity_constraints
WHERE max_gradient > 5;

SELECT compliance_date, regulation_type, compliance_status 
FROM regulatory_compliance 
WHERE facility_id = 1;

SELECT facility_id, SUM(fixed_cost) AS total_fixed_cost, SUM(variable_cost) AS total_variable_cost
FROM costs
GROUP BY facility_id;

SELECT facilities.facility_id, sites.site_name
FROM facilities
INNER JOIN sites ON facilities.site_id = sites.site_id;

external_knowledge:
- "beacons of industry" is a metaphorical term for facilities;
- "Golden State" is a metaphorical term for California;
- "reached the zenith of their spatial requirements" means they have the maximum area required per unit of capacity;
- "identifiers" refer to facility IDs;
- "harbors" refer to the sites;
- "processes they embody" refers to the process names;
- "peak space needed for their capacity" refers to the maximum area per capacity.

sql:
SELECT facility_id, installed_capacity
FROM facilities
WHERE installed_capacity = (
    SELECT MAX(installed_capacity) FROM facilities
);

external_knowledge:
- Significant capacity fluctuation potential: This refers to facilities with a maximum gradient greater than 10% of their installed capacity. This criterion implies that the facility can adjust its operational capacity quite flexibly;
- Overall spending: This encompasses the sum of investment, fixed, and variable costs;
- Total area occupied: This is the sum of the area required per unit of capacity for these facilities.

sql:
SELECT AVG(investment_cost) AS average_investment_cost
FROM facilities
WHERE energy_type = 'Solar';

SELECT site_name, location
FROM sites
ORDER BY site_name;
